    (9, 'Refusal Skills – Social Media & SRH', 'refusal-skills-social-media', 'interactive', 'interactive/lesson-refusal-social-media.html', 99, 1, 1),
    (18, 'Refusal Skills – Gambling', 'refusal-skills-gambling', 'interactive', 'interactive/lesson-refusal-gambling.html', 99, 1, 1),
